def _build_subject(notification_type: str, event: Dict[str, Any]) -> str:
    subject = _get_event_value(event, "subject", "Subject")
    if subject:
        return str(subject)[:100]

    env_subject_prefix = os.getenv("SUBJECT_PREFIX", "").strip()
    base_subject = DEFAULT_SUBJECTS.get(notification_type.lower(), "Notification")
    final_subject = f"{env_subject_prefix} {base_subject}".strip()
    return final_subject[:100]


def _build_message(notification_type: str, message_content: Any, event: Dict[str, Any]) -> str:
    if notification_type.lower() == "event":
        payload = {
            "notificationType": notification_type,
            "message": message_content,
            "metadata": _get_event_value(event, "metadata", "meta", default={}),
            "source": _get_event_value(event, "source", default="event-notification-system"),
            "timestamp": _get_event_value(event, "timestamp"),
        }
